  # Helper to clean quoted objects and remove parenthetical units
          def clean_obj(o: str) -> str:
              # Remove surrounding quotes
              cleaned = o.strip('"').strip("'")
              # Remove parenthetical content like "(metres)" or "(square metres)"
              if "(" in cleaned and ")" in cleaned:
                  cleaned = cleaned.split("(")[0].strip()
              return cleaned
